function OpenAIIcon({ active, color }: { active: boolean; color: string }) {
  return (
    <svg viewBox="0 0 24 24" className="h-5 w-5" fill="none">
      <path
        d={OPENAI_PATH}
        fill={active ? color : "currentColor"}
        opacity={active ? 1 : 0.4}
      />
    </svg>
  );
}

function ClaudeIcon({ active, color }: { active: boolean; color: string }) {
  return (
    <svg viewBox="0 0 24 24" className="h-5 w-5" fill="none">
      <path
        d={CLAUDE_PATH}
        fill={active ? color : "currentColor"}
        opacity={active ? 1 : 0.4}
      />
    </svg>
  );
}

function OllamaIcon({ active }: { active: boolean; color: string }) {
  const { theme } = useTheme();
  const activeFill = theme === "dark" ? "#ffffff" : "#000000";
  if (!active) {
    return (
      <svg viewBox="0 0 24 24" className="h-5 w-5" fill="none">
        <path d={OLLAMA_PATH} fill="currentColor" opacity={0.4} />
      </svg>
    );
  }
  return (
    <svg viewBox="0 0 24 24" className="h-5 w-5" fill="none">
      <path d={OLLAMA_PATH} fill={activeFill} />
    </svg>
  );
}

function GeminiIcon({ active }: { active: boolean; color: string }) {
  if (!active) {
    return (
      <svg viewBox="0 0 24 24" className="h-5 w-5" fill="none">
        <path d={GEMINI_PATH} fill="currentColor" opacity={0.4} />
      </svg>
    );
  }
  return (
    <svg viewBox="0 0 24 24" className="h-5 w-5" fill="none">
      <defs>
        <linearGradient gradientUnits="userSpaceOnUse" id="gemini-sw-g0" x1="7" x2="11" y1="15.5" y2="12">
          <stop stopColor="#08B962" />
          <stop offset="1" stopColor="#08B962" stopOpacity="0" />
        </linearGradient>
        <linearGradient gradientUnits="userSpaceOnUse" id="gemini-sw-g1" x1="8" x2="11.5" y1="5.5" y2="11">
          <stop stopColor="#F94543" />
          <stop offset="1" stopColor="#F94543" stopOpacity="0" />
        </linearGradient>
        <linearGradient gradientUnits="userSpaceOnUse" id="gemini-sw-g2" x1="3.5" x2="17.5" y1="13.5" y2="12">
          <stop stopColor="#FABC12" />
          <stop offset=".46" stopColor="#FABC12" stopOpacity="0" />
        </linearGradient>
      </defs>
      <path d={GEMINI_PATH} fill="#3186FF" />
      <path d={GEMINI_PATH} fill="url(#gemini-sw-g0)" />
      <path d={GEMINI_PATH} fill="url(#gemini-sw-g1)" />
      <path d={GEMINI_PATH} fill="url(#gemini-sw-g2)" />
    </svg>
  );
}

const ICON_MAP: Record<LLMProviderName, React.FC<{ active: boolean; color: string }>> = {
  openai: OpenAIIcon,
  anthropic: ClaudeIcon,
  gemini: GeminiIcon,
  ollama: OllamaIcon,
};

export function ProviderSwitcher({ activeProvider, onSwitch, disabled }: ProviderSwitcherProps) {
  return (
    <div className="flex items-center gap-0.5">
      {PROVIDERS.map((p) => {
        const isActive = activeProvider === p.name;
        const Icon = ICON_MAP[p.name];
        return (
          <button
            key={p.name}
            title={p.label}
            disabled={disabled}
            onClick={() => {
              if (!isActive) onSwitch(p.name);
            }}
            className={`rounded-md p-1.5 transition-colors ${
              isActive
                ? "bg-accent"
                : "opacity-60 hover:opacity-100 hover:bg-accent/50"
            } disabled:pointer-events-none disabled:opacity-30`}
          >
            <Icon active={isActive} color={p.color} />
          </button>
        );
      })}
    </div>
  );
}
